python3 << 'EOF'
import re

with open('/tmp/alb-data/ALB-027.txt', 'r') as f:
    content = f.read()

round_pattern = re.compile(r'\[USER\]: Round (\d+): Guess')
rounds = list(round_pattern.finditer(content))

# Extract the feedback section (before TOOL RESULT) for each round
weights = {'Type': 6, 'Abilities': 5, 'Base Stats': 4, 'Evolution': 3, 'Generation': 2, 'Other': 1}

for target_round in [5, 28]:
    for i, m in enumerate(rounds):
        if int(m.group(1)) == target_round:
            start = m.end()
            if i + 1 < len(rounds):
                end = rounds[i+1].start()
            else:
                end = len(content)
            section = content[start:end]

            # Get only the feedback part (before [TOOL RESULT] or [ASSISTANT])
            tool_idx = section.find('[TOOL RESULT]')
            if tool_idx == -1:
                tool_idx = section.find('[ASSISTANT]')
            if tool_idx != -1:
                feedback = section[:tool_idx]
            else:
                feedback = section

            print(f"\n=== Round {target_round} feedback ===")
            print(feedback)

            # Count (correct) per section
            # Split by section headers
            score = 0
            for section_name, weight in weights.items():
                # Find the section
                pattern = rf'- {re.escape(section_name)}:'
                sec_match = re.search(pattern, feedback)
                if sec_match:
                    # Get text from this match to next section or end
                    sec_start = sec_match.end()
                    next_sec = re.search(r'\n  - \w+[\w ]*:', feedback[sec_start:])
                    if next_sec:
                        sec_text = feedback[sec_start:sec_start + next_sec.start()]
                    else:
                        sec_text = feedback[sec_start:]
                    correct_count = sec_text.count('(correct)')
                    print(f"  {section_name}: {correct_count} correct × {weight} = {correct_count * weight}")
                    score += correct_count * weight

            print(f"  TOTAL SCORE: {score}")
            break
EOF
